/**
 * Email notification adapter.
 *
 * Implements the NotificationAdapter interface for the 'email' channel.
 * Provides template rendering, recipient validation, and configurable
 * transport for sending emails.
 */

import type { NotificationAdapter, NotificationResult } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload, NotificationType } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/** Configuration for the email adapter. */
export interface EmailConfig {
  /** Sender email address shown in the From field. */
  from: string;
  /** SMTP host for sending emails. */
  host: string;
  /** SMTP port. */
  port: number;
  /** Whether to use TLS. */
  secure: boolean;
}

/** Default email configuration. */
export const defaultEmailConfig: EmailConfig = {
  from: 'noreply@taskflowpro.com',
  host: 'localhost',
  port: 587,
  secure: false,
};

/** Record of an email that was sent. */
export interface SentEmail {
  to: string;
  from: string;
  subject: string;
  body: string;
  html: string;
  sentAt: Date;
}

/**
 * Transport interface for actually sending emails.
 * Allows swapping between real SMTP and test/in-memory transports.
 */
export interface EmailTransport {
  sendMail(options: {
    from: string;
    to: string;
    subject: string;
    text: string;
    html: string;
  }): Promise<{ messageId: string }>;
}

/**
 * In-memory email transport for testing and development.
 * Stores all sent emails and allows inspection.
 */
export class InMemoryTransport implements EmailTransport {
  private inbox: SentEmail[] = [];

  async sendMail(options: {
    from: string;
    to: string;
    subject: string;
    text: string;
    html: string;
  }): Promise<{ messageId: string }> {
    const email: SentEmail = {
      to: options.to,
      from: options.from,
      subject: options.subject,
      body: options.text,
      html: options.html,
      sentAt: new Date(),
    };
    this.inbox.push(email);
    return { messageId: `msg-${this.inbox.length}` };
  }

  getEmails(): SentEmail[] {
    return [...this.inbox];
  }

  clear(): void {
    this.inbox = [];
  }
}

/** Template data extracted from a notification payload. */
interface TemplateData {
  recipient: string;
  subject: string;
  body: string;
  type: NotificationType;
  priority: string;
  metadata: Record<string, string>;
}

/**
 * Email templates keyed by notification type.
 * Each returns { subject, text, html } for the email.
 */
const emailTemplates: Record<
  NotificationType,
  (data: TemplateData) => { subject: string; text: string; html: string }
> = {
  order_confirmation: (data) => ({
    subject: data.subject,
    text: data.body,
    html: renderHtml('Order Confirmation', data.body, 'thank you'),
  }),
  order_status_update: (data) => ({
    subject: data.subject,
    text: data.body,
    html: renderHtml('Order Status Update', data.body, 'status update'),
  }),
  user_welcome: (data) => ({
    subject: data.subject,
    text: data.body,
    html: renderHtml('Welcome to TaskFlow Pro', data.body, 'welcome'),
  }),
  user_update: (data) => ({
    subject: data.subject,
    text: data.body,
    html: renderHtml('Account Update', data.body, 'account'),
  }),
  system_alert: (data) => ({
    subject: `[ALERT] ${data.subject}`,
    text: data.body,
    html: renderHtml('System Alert', data.body, 'alert'),
  }),
};

/**
 * Render a simple HTML email wrapper.
 */
function renderHtml(title: string, bodyText: string, category: string): string {
  return [
    '<!DOCTYPE html>',
    '<html>',
    '<head><meta charset="utf-8"></head>',
    '<body>',
    `<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">`,
    `<h1 style="color: #333;">${escapeHtml(title)}</h1>`,
    `<p>${escapeHtml(bodyText)}</p>`,
    `<hr>`,
    `<p style="color: #999; font-size: 12px;">Category: ${escapeHtml(category)} | TaskFlow Pro</p>`,
    '</div>',
    '</body>',
    '</html>',
  ].join('\n');
}

/**
 * Escape HTML special characters to prevent XSS in email templates.
 */
function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

/** Simple email address validation. */
function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private config: EmailConfig;
  private transport: EmailTransport;

  constructor(config?: Partial<EmailConfig>, transport?: EmailTransport) {
    this.config = { ...defaultEmailConfig, ...config };
    this.transport = transport ?? new InMemoryTransport();
  }

  /**
   * Send an email notification.
   * Validates the recipient, renders the template, and sends via transport.
   * Never throws — returns a failed NotificationResult on error.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // Validate recipient
      const recipient = this.resolveRecipient(payload);
      if (!recipient) {
        const error = `Invalid or missing recipient: ${payload.recipient}`;
        this.logger.error(error);
        return { success: false, error };
      }

      // Render template
      const templateData: TemplateData = {
        recipient,
        subject: payload.subject,
        body: payload.body,
        type: payload.type,
        priority: payload.priority,
        metadata: payload.metadata ?? {},
      };

      const rendered = this.renderTemplate(payload.type, templateData);

      // Send via transport
      this.logger.info(`Sending email to ${recipient}: ${rendered.subject}`);
      const result = await this.transport.sendMail({
        from: this.config.from,
        to: recipient,
        subject: rendered.subject,
        text: rendered.text,
        html: rendered.html,
      });

      this.logger.info(`Email sent successfully: ${result.messageId}`);
      return {
        success: true,
        externalId: result.messageId,
      };
    } catch (err: unknown) {
      const error = err instanceof Error ? err.message : 'Unknown email send error';
      this.logger.error(`Failed to send email: ${error}`);
      return { success: false, error };
    }
  }

  /**
   * Resolve and validate the recipient email address.
   * Returns null if the address is invalid.
   */
  private resolveRecipient(payload: NotificationPayload): string | null {
    const email = payload.recipient.trim().toLowerCase();
    if (!isValidEmail(email)) {
      return null;
    }
    return email;
  }

  /**
   * Render the email content using the appropriate template for the notification type.
   */
  private renderTemplate(
    type: NotificationType,
    data: TemplateData,
  ): { subject: string; text: string; html: string } {
    const template = emailTemplates[type];
    return template(data);
  }

  /**
   * Get the underlying transport (useful for testing with InMemoryTransport).
   */
  getTransport(): EmailTransport {
    return this.transport;
  }

  /**
   * Get all sent emails. Only works if using InMemoryTransport.
   */
  getSentEmails(): SentEmail[] {
    if (this.transport instanceof InMemoryTransport) {
      return this.transport.getEmails();
    }
    return [];
  }

  /**
   * Clear sent emails. Only works if using InMemoryTransport.
   */
  clearSentEmails(): void {
    if (this.transport instanceof InMemoryTransport) {
      this.transport.clear();
    }
  }
}

