import { describe, it, expect, beforeEach } from 'vitest';
import {
  EmailAdapter,
  InMemoryTransport,
  defaultEmailConfig,
} from '../../src/adapters/email.adapter.js';
import type { EmailTransport } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    channel: 'email',
    type: 'order_confirmation',
    priority: 'normal',
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;
  let transport: InMemoryTransport;

  beforeEach(() => {
    transport = new InMemoryTransport();
    adapter = new EmailAdapter(undefined, transport);
  });

  it('should have channel set to email', () => {
    expect(adapter.channel).toBe('email');
  });

  describe('send', () => {
    it('should send an email and return success', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.externalId).toBeDefined();
    });

    it('should deliver email to the transport', async () => {
      await adapter.send(makePayload());

      const emails = transport.getEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.from).toBe(defaultEmailConfig.from);
      expect(emails[0]?.subject).toBe('Order Confirmation: order-1');
      expect(emails[0]?.body).toContain('Widget x2');
    });

    it('should generate HTML content', async () => {
      await adapter.send(makePayload());

      const emails = transport.getEmails();
      expect(emails[0]?.html).toContain('<!DOCTYPE html>');
      expect(emails[0]?.html).toContain('Order Confirmation');
      expect(emails[0]?.html).toContain('Widget x2');
    });

    it('should normalize recipient to lowercase', async () => {
      await adapter.send(makePayload({ recipient: 'Alice@Example.COM' }));

      const emails = transport.getEmails();
      expect(emails[0]?.to).toBe('alice@example.com');
    });

    it('should trim whitespace from recipient', async () => {
      await adapter.send(makePayload({ recipient: '  alice@example.com  ' }));

      const emails = transport.getEmails();
      expect(emails[0]?.to).toBe('alice@example.com');
    });

    it('should use custom from address', async () => {
      const customAdapter = new EmailAdapter({ from: 'custom@company.com' }, transport);
      await customAdapter.send(makePayload());

      const emails = transport.getEmails();
      expect(emails[0]?.from).toBe('custom@company.com');
    });
  });

  describe('recipient validation', () => {
    it('should reject empty recipient', async () => {
      const result = await adapter.send(makePayload({ recipient: '' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid or missing recipient');
    });

    it('should reject recipient without @', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-an-email' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid or missing recipient');
    });

    it('should reject recipient without domain', async () => {
      const result = await adapter.send(makePayload({ recipient: 'user@' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid or missing recipient');
    });

    it('should not send email when recipient is invalid', async () => {
      await adapter.send(makePayload({ recipient: 'invalid' }));

      expect(transport.getEmails()).toHaveLength(0);
    });
  });

  describe('template rendering', () => {
    it('should render order_confirmation template', async () => {
      await adapter.send(makePayload({ type: 'order_confirmation' }));

      const emails = transport.getEmails();
      expect(emails[0]?.html).toContain('Order Confirmation');
      expect(emails[0]?.html).toContain('thank you');
    });

    it('should render order_status_update template', async () => {
      await adapter.send(
        makePayload({
          type: 'order_status_update',
          subject: 'Order Update: order-1',
          body: 'Your order status has changed from pending to confirmed.',
        }),
      );

      const emails = transport.getEmails();
      expect(emails[0]?.html).toContain('Order Status Update');
      expect(emails[0]?.html).toContain('status update');
    });

    it('should render system_alert template with prefix', async () => {
      await adapter.send(
        makePayload({
          type: 'system_alert',
          subject: 'High CPU Usage',
          body: 'CPU usage exceeded 90%.',
        }),
      );

      const emails = transport.getEmails();
      expect(emails[0]?.subject).toBe('[ALERT] High CPU Usage');
    });

    it('should render user_welcome template', async () => {
      await adapter.send(
        makePayload({
          type: 'user_welcome',
          subject: 'Welcome!',
          body: 'Welcome to TaskFlow Pro.',
        }),
      );

      const emails = transport.getEmails();
      expect(emails[0]?.html).toContain('Welcome to TaskFlow Pro');
      expect(emails[0]?.html).toContain('welcome');
    });

    it('should render user_update template', async () => {
      await adapter.send(
        makePayload({
          type: 'user_update',
          subject: 'Account Updated',
          body: 'Your profile has been updated.',
        }),
      );

      const emails = transport.getEmails();
      expect(emails[0]?.html).toContain('Account Update');
      expect(emails[0]?.html).toContain('account');
    });

    it('should escape HTML in body to prevent XSS', async () => {
      await adapter.send(
        makePayload({
          body: '<script>alert("xss")</script>',
        }),
      );

      const emails = transport.getEmails();
      expect(emails[0]?.html).not.toContain('<script>');
      expect(emails[0]?.html).toContain('&lt;script&gt;');
    });
  });

  describe('transport error handling', () => {
    it('should return failure when transport throws', async () => {
      const failingTransport: EmailTransport = {
        async sendMail() {
          throw new Error('SMTP connection refused');
        },
      };
      const failAdapter = new EmailAdapter(undefined, failingTransport);

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMTP connection refused');
    });

    it('should handle non-Error thrown values', async () => {
      const failingTransport: EmailTransport = {
        async sendMail() {
          throw 'string error';
        },
      };
      const failAdapter = new EmailAdapter(undefined, failingTransport);

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Unknown email send error');
    });
  });

  describe('getSentEmails / clearSentEmails', () => {
    it('should return sent emails from InMemoryTransport', async () => {
      await adapter.send(makePayload());
      await adapter.send(makePayload({ recipient: 'bob@example.com' }));

      const sent = adapter.getSentEmails();
      expect(sent).toHaveLength(2);
      expect(sent[0]?.to).toBe('alice@example.com');
      expect(sent[1]?.to).toBe('bob@example.com');
    });

    it('should clear sent emails', async () => {
      await adapter.send(makePayload());
      adapter.clearSentEmails();

      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should return empty array for non-InMemoryTransport', () => {
      const customTransport: EmailTransport = {
        async sendMail() {
          return { messageId: 'ext-1' };
        },
      };
      const customAdapter = new EmailAdapter(undefined, customTransport);

      expect(customAdapter.getSentEmails()).toEqual([]);
    });
  });

  describe('getTransport', () => {
    it('should expose the transport instance', () => {
      expect(adapter.getTransport()).toBe(transport);
    });
  });
});

describe('InMemoryTransport', () => {
  let transport: InMemoryTransport;

  beforeEach(() => {
    transport = new InMemoryTransport();
  });

  it('should store sent emails', async () => {
    await transport.sendMail({
      from: 'a@b.com',
      to: 'c@d.com',
      subject: 'Test',
      text: 'Hello',
      html: '<p>Hello</p>',
    });

    const emails = transport.getEmails();
    expect(emails).toHaveLength(1);
    expect(emails[0]?.to).toBe('c@d.com');
    expect(emails[0]?.subject).toBe('Test');
  });

  it('should return sequential message IDs', async () => {
    const r1 = await transport.sendMail({
      from: 'a@b.com',
      to: 'c@d.com',
      subject: 'First',
      text: '',
      html: '',
    });
    const r2 = await transport.sendMail({
      from: 'a@b.com',
      to: 'c@d.com',
      subject: 'Second',
      text: '',
      html: '',
    });

    expect(r1.messageId).toBe('msg-1');
    expect(r2.messageId).toBe('msg-2');
  });

  it('should clear all emails', async () => {
    await transport.sendMail({
      from: 'a@b.com',
      to: 'c@d.com',
      subject: 'Test',
      text: '',
      html: '',
    });
    transport.clear();

    expect(transport.getEmails()).toHaveLength(0);
  });

  it('should return copies of emails, not references', async () => {
    await transport.sendMail({
      from: 'a@b.com',
      to: 'c@d.com',
      subject: 'Test',
      text: '',
      html: '',
    });

    const first = transport.getEmails();
    const second = transport.getEmails();
    expect(first).not.toBe(second);
    expect(first).toEqual(second);
  });
});

